#!/usr/bin/perl
use strict;
use warnings;
use CGI;
use URI;

my $cgi = CGI->new();

my $redirect_url = $cgi->param('next');

my @allowed_hosts = (
    'www.example.com',
    'app.example.com',
    'example.com',
);

my $default_url = '/dashboard';

sub is_safe_redirect {
    my ($url) = @_;

    return 0 unless defined $url && $url ne '';

    # Block URLs with newline characters to prevent header injection
    return 0 if $url =~ /[\r\n]/;

    # Allow relative URLs starting with /
    if ($url =~ m{^/[^/\\]}) {
        return 1;
    }

    # For absolute URLs, validate the scheme and host
    my $uri = eval { URI->new($url) };
    return 0 unless $uri;

    my $scheme = $uri->scheme // '';
    return 0 unless $scheme eq 'http' || $scheme eq 'https';

    my $host = $uri->host // '';
    return 0 unless $host ne '';

    foreach my $allowed (@allowed_hosts) {
        if (lc($host) eq lc($allowed)) {
            return 1;
        }
    }

    return 0;
}

sub verify_session {
    my $session_cookie = $cgi->cookie('session_id');

    unless (defined $session_cookie && $session_cookie =~ /^[a-zA-Z0-9]{32,64}$/) {
        return 0;
    }

    # In a real implementation, validate the session against a session store
    # e.g., database lookup, Redis check, etc.
    return 1;
}

# Verify the user is actually authenticated before redirecting
unless (verify_session()) {
    print $cgi->header(
        -type   => 'text/html',
        -status => '403 Forbidden',
    );
    print "<html><body><h1>403 Forbidden</h1><p>You must be logged in to access this resource.</p>";
    print '<p><a href="/login">Go to Login</a></p></body></html>';
    exit 0;
}

# Validate and sanitize the redirect URL
if (is_safe_redirect($redirect_url)) {
    # URL is safe — perform the redirect
    print $cgi->redirect(
        -uri    => $redirect_url,
        -status => '302 Found',
    );
} else {
    # Invalid or missing redirect URL — send to default safe location
    if (defined $redirect_url && $redirect_url ne '') {
        # Log the suspicious redirect attempt
        warn "Blocked potentially unsafe redirect attempt to: $redirect_url from IP: " . ($ENV{'REMOTE_ADDR'} // 'unknown');
    }

    print $cgi->redirect(
        -uri    => $default_url,
        -status => '302 Found',
    );
}

exit 0;